#include <bits/stdc++.h>
using namespace std;

const int N=5e5+5;

struct Node{
    int x,e;
}p[N];

bool cmp1(Node u,Node v){
    return u.x<v.x;
}

bool cmp2(Node u,Node v){
    return u.e>v.e;
}

int n,ans,c[2][N],cnt;
map<int,int> id;

int lowbit(int x){
	return x&(-x);
}

int query(int x,int tp){
	if(!x)
		return 2e9;
	return min(c[tp][x],query(x-lowbit(x),tp));
}

void modify(int x,int num,int tp){
	if(x>cnt)
		return;
	c[tp][x]=min(c[tp][x],num);
	modify(x+lowbit(x),num,tp);
}

int main(){
	memset(c,127,sizeof(c));
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&p[i].x,&p[i].e);
    sort(p+1,p+n+1,cmp1);
    for(int i=1;i<=n;i++)
    	if(i==1 || p[i].x!=p[i-1].x)
			id[p[i].x]=++cnt;
    sort(p+1,p+n+1,cmp2);
    for(int i=1;i<=n;i++,ans++){
        if(-p[i].x-p[i].e>=query(id[p[i].x],0) || p[i].x-p[i].e>=query(cnt-id[p[i].x]+1,1))
            ans--;
        else
            modify(id[p[i].x],-p[i].x-p[i].e,0),modify(cnt-id[p[i].x]+1,p[i].x-p[i].e,1);
    }
    printf("%d",ans);
    return 0;
}
